(v: number, numberDecimalPlaces?: number) =>
    new Intl.NumberFormat(getActiveLanguage(), {
        minimumFractionDigits: numberDecimalPlaces,
        maximumFractionDigits: numberDecimalPlaces ?? 20,
    }).format(v)

